    decimal = abs(n - int(n))

    # If exactly 0.5
    if decimal == 0.5:
        # Round to nearest even number
        floor = int(n)
        if floor % 2 == 0:
            return floor
        else:
            return floor + 1
    # Otherwise use regular rounding
    else:
        return round(n)

