def is_ipv4(target):

    # Check if target is string
    if not isinstance(target, str):
        return False

    # Split into octets
    octets = target.split('.')

    # IPv4 must have 4 octets
    if len(octets) != 4:
        return False

    # Check each octet
    for octet in octets:
        # Check if octet is numeric
        if not octet.isdigit():
            return False

        # Convert to integer
        num = int(octet)

        # Check range 0-255
        if num < 0 or num > 255:
            return False

        # Leading zeros not allowed
        if len(octet) > 1 and octet[0] == '0':
            return False

    return True

